const STOP = new Set(["the","a","with","and","press","bodyweight","machine","your"]);
const stem = (w: string) => (w.length > 3 && w.endsWith("s") && !/(ss|us|is)$/.test(w)) ? w.slice(0, -1) : w;
const toks = (s: string) => s.toLowerCase().replace(/[^a-z0-9 ]/g, " ").split(/s+/).filter((w) => w && !STOP.has(w)).map(stem);
export function findDemo(query: string): ExerciseDemo | null {
  const q = toks(query); if (!q.length) return null;
  let best: ExerciseDemo | null = null, score = 0;
  for (const d of EXERCISE_DEMOS) { const dt = toks(d.key + " " + d.name); let s = 0; for (const t of q) if (dt.includes(t)) s += 1; if (s > score) { score = s; best = d; } }
  return score >= 1 ? best : null;
}
